{"command": "cd /app/data/auto-opt/utils/llvm-85265 && cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp 8792 8792
  // fcmp pred (fptrunc X), C -> fcmp pred X, adjustedC
  if (match(Op0, m_FPTrunc(m_Value(X)))) {
    // fcmp (fptrunc X), (fptrunc Y) -> fcmp X, Y
    if (match(Op1, m_FPTrunc(m_Value(Y))) && X->getType() == Y->getType())
      return new FCmpInst(Pred, X, Y, "", &I);

    const APFloat *C;
    if (match(Op1, m_APFloat(C))) {
      Type *SrcTy = X->getType();
      Type *DstTy = Op0->getType();
      const fltSemantics &SrcSem = SrcTy->getScalarType()->getFltSemantics();
      const fltSemantics &DstSem = DstTy->getScalarType()->getFltSemantics();
      // Convert constant to source type (exact)
      bool Lossy;
      APFloat CSrc = *C;
      Lossy = CSrc.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy) != APFloat::opOK;
      // Lossy should be false because widening.
      if (Lossy)
        return nullptr;

      // Compute ulp in destination semantics.
      APFloat CUp = *C;
      APFloat::opStatus Status = CUp.next(/*nextDown=*/false);
      (void)Status;
      APFloat Ulp = CUp;
      Ulp.subtract(*C, APFloat::rmNearestTiesToEven);
      // Convert Ulp to source semantics (exact)
      Lossy = Ulp.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy) != APFloat::opOK;
      if (Lossy)
        return nullptr;
      APFloat HalfUlp = Ulp;
      HalfUlp.divide(APFloat(SrcSem, 2), APFloat::rmNearestTiesToEven);
      APFloat Lower = CSrc;
      Lower.subtract(HalfUlp, APFloat::rmNearestTiesToEven);
      APFloat Upper = CSrc;
      Upper.add(HalfUlp, APFloat::rmNearestTiesToEven);

      // Map predicate to new constant
      APFloat NewC = CSrc;
      switch (Pred) {
      default:
        break;
      case FCmpInst::FCMP_OGE:
      case FCmpInst::FCMP_UGE:
        NewC = Lower;
        break;
      case FCmpInst::FCMP_OLE:
      case FCmpInst::FCMP_ULE:
        NewC = Upper;
        break;
      // TODO: Handle other predicates.
      }
      if (NewC != CSrc) {
        Constant *NewConst = ConstantFP::get(SrcTy, NewC);
        return new FCmpInst(Pred, X, NewConst, "", &I);
      }
    }
  }

CODEEOF"}

