    const APFloat *CFloat = nullptr;
    Constant *C = nullptr;
    if (match(Op1, m_Constant(C))) {
      if (auto *CFP = dyn_cast<ConstantFP>(C)) {
        CFloat = &CFP->getValueAPF();
      } else if (auto *CDV = dyn_cast<ConstantDataVector>(C)) {
        if (CDV->isSplat())
          CFloat = &CDV->getSplatValue()->getValueAPF();
      } else if (auto *CV = dyn_cast<ConstantVector>(C)) {
        if (CV->isSplat())
          if (auto *CFP = dyn_cast<ConstantFP>(CV->getSplatValue()))
            CFloat = &CFP->getValueAPF();
      }
    }
    if (!CFloat)
      return nullptr;

    Type *SrcTy = X->getType();
    Type *DstTy = Op0->getType();
    const fltSemantics &SrcSem = SrcTy->getScalarType()->getFltSemantics();
    const fltSemantics &DstSem = DstTy->getScalarType()->getFltSemantics();
    // Reject infinity and NaN.
    if (CFloat->isNaN() || CFloat->isInfinity())
      return nullptr;
    // Convert constant to source type (exact)
    bool Lossy;
    APFloat CSrc = *CFloat;
    Lossy = CSrc.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy) != APFloat::opOK;
    // Lossy should be false because widening.
    if (Lossy)
      return nullptr;

    // Compute ulp in destination semantics.
    APFloat CUp = *CFloat;
    APFloat::opStatus Status = CUp.next(/*nextDown=*/false);
    (void)Status;
    APFloat Ulp = CUp;
    Ulp.subtract(*CFloat, APFloat::rmNearestTiesToEven);
    // Convert Ulp to source semantics (exact)
    Lossy = Ulp.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy) != APFloat::opOK;
    if (Lossy)
      return nullptr;
    APFloat HalfUlp = Ulp;
    HalfUlp.divide(APFloat(SrcSem, 2), APFloat::rmNearestTiesToEven);
    APFloat Lower = CSrc;
    Lower.subtract(HalfUlp, APFloat::rmNearestTiesToEven);
    APFloat Upper = CSrc;
    Upper.add(HalfUlp, APFloat::rmNearestTiesToEven);

    // Map predicate to new constant
    APFloat NewC = CSrc;
    switch (Pred) {
    default:
      break;
    case FCmpInst::FCMP_OGE:
    case FCmpInst::FCMP_UGE:
      NewC = Lower;
      break;
    case FCmpInst::FCMP_OLE:
    case FCmpInst::FCMP_ULE:
      NewC = Upper;
      break;
    case FCmpInst::FCMP_OGT:
    case FCmpInst::FCMP_UGT:
      NewC = Upper;
      break;
    case FCmpInst::FCMP_OLT:
    case FCmpInst::FCMP_ULT:
      NewC = Lower;
      break;
    // TODO: Handle equality predicates.
    }
    if (NewC != CSrc) {
      Constant *NewConst = nullptr;
      if (auto *VecTy = dyn_cast<VectorType>(SrcTy)) {
        NewConst = ConstantDataVector::getSplat(VecTy->getElementCount(),
                                                ConstantFP::get(SrcTy->getScalarType(), NewC));
      } else {
        NewConst = ConstantFP::get(SrcTy, NewC);
      }
      return new FCmpInst(Pred, X, NewConst, "", &I);
    }
